import React, { useState, useEffect } from 'react';
import ProgressBar from 'react-bootstrap/ProgressBar';

function ScrollProgressBar({ parallaxRef }) {
  const [scrollPercentage, setScrollPercentage] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
      const scrollTop = parallaxRef.current.current;
      const scrollHeight = parallaxRef.current.pages * window.innerHeight - window.innerHeight;
      const percentage = (scrollTop / scrollHeight) * 100;
      setScrollPercentage(percentage);
    };

    const scrollListener = parallaxRef.current.scroll.subscribe(handleScroll);
    return () => {
      scrollListener.unsubscribe();
    };
  }, [parallaxRef]);

  return (
    <ProgressBar now={scrollPercentage} />
  );
}

export default ScrollProgressBar;
